let calendarEvents = [];
const dayNames = ["Neděle","Pondělí","Úterý","Středa","Čtvrtek","Pátek","Sobota"];
let events = [];
let longEvents = [];
let calendarSignatureV300 = "";

function uid(){ return Date.now().toString(36) + Math.random().toString(36).slice(2); }
function pad(n){ return String(n).padStart(2,"0"); }
function parseDate(value){ if(!value) return null; const [y,m,d]=value.split("-").map(Number); return new Date(y,m-1,d); }
function dateToInput(d){ return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`; }
function formatDate(value){ const d=parseDate(value); return d ? `${d.getDate()}.${d.getMonth()+1}.${d.getFullYear()}` : ""; }
function formatDateShort(value){ const d=parseDate(value); return d ? `${d.getDate()}.${d.getMonth()+1}.` : ""; }
function formatTime(t){ if(!t) return ""; const [h,m]=t.split(":"); return `${Number(h)}.${m}`; }
function timeRange(a,b){ if(a&&b) return `${formatTime(a)} – ${formatTime(b)}`; if(a) return formatTime(a); return ""; }
function escapeHtml(s){ return String(s||"").replace(/[&<>"']/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[m])); }

function getWeekDates(){
  const from=parseDate(document.getElementById("weekFrom").value);
  const to=parseDate(document.getElementById("weekTo").value);
  if(!from||!to) return [];
  const out=[]; const d=new Date(from);
  while(d<=to){ out.push(new Date(d)); d.setDate(d.getDate()+1); }
  return out;
}
function inSelectedWeek(ev){
  const from = document.getElementById("weekFrom").value;
  const to = document.getElementById("weekTo").value;
  if(!from || !to) return false;
  return ev.startDate <= to && ev.endDate >= from;
}
function sortEvents(list){
  return [...list].sort((a,b)=>{
    const d=(a.date||"").localeCompare(b.date||"");
    if(d!==0) return d;
    return eventSortMinutesV300(a.from) - eventSortMinutesV300(b.from);
  });
}
function isReservation(ev){
  return /rezervovaná učebna|změnit učebnu/i.test(ev.summary || "");
}
function isSubjectEvent(ev){
  return !!ev.subject || /test|čtvrtlet|slovíčka|lesson|unit|diktát|písemná práce|opakování/i.test(ev.summary || "");
}
function eventTitleFromCalendar(ev){
  const parts = [];
  if(ev.classes) parts.push(ev.classes);
  parts.push(ev.summary);
  if(ev.location && !/iPad/i.test(ev.location)) parts.push(`(${ev.location})`);
  return parts.join(" ");
}
function eventPersonFromCalendar(ev){
  return ev.teachers || "";
}

function importEmbeddedCalendar(){
  calendarEvents = [];
  calendarSignatureV300 = "";
  events = [];
  longEvents = [];
  setCalendarBadgeV300("error", "EduPage nepřipojeno", "Záložní kalendář je vypnutý.");
  setPreviewStatusV300("EduPage kalendář není připojený", "Záložní data jsou vypnutá, aby plán nikdy nevycházel ze starého kalendáře.");
}
function setCalendarInfo(){
  const dates = calendarEvents.map(e=>e.startDate).filter(Boolean).sort();
  const detail = dates.length ? `${calendarEvents.length} událostí · ${dates[0]} až ${dates[dates.length-1]}` : "Kalendář je prázdný.";
  setCalendarBadgeV300("connected", "EduPage připojeno", detail);
}

let topEduLoadingStartedV314 = 0;
let topEduStatusTimerV314 = null;

function setCalendarBadgeV300(state, text, detail){
  const holder = document.getElementById("calendarInfo");
  updateTopEduStatusV312(state, text, detail);
  if(!holder) return;

  let badge = holder.querySelector(".eduBadgeLockV89");
  if(!badge){
    badge = document.createElement("div");
    badge.className = "eduBadgeLockV89";
    badge.innerHTML = '<span class="dot"></span><span class="txt"></span>';
    holder.replaceChildren(badge);
  }

  badge.className = `eduBadgeLockV89 ${state || "connected"}`;
  const label = badge.querySelector(".txt");
  if(label) label.textContent = text || "EduPage připojeno";
  if(detail) badge.title = detail;
}

function updateTopEduStatusV312(state, text, detail){
  const badge = document.querySelector(".top .subtitle");
  if(!badge) return;
  const normalized = state || "connected";

  const applyStatus = () => {
    badge.classList.remove("eduState-connectedV312", "eduState-loadingV312", "eduState-errorV312");
    badge.classList.add(`eduState-${normalized}V312`);
    const labelText = text || (normalized === "loading" ? "EduPage načítání" : normalized === "error" ? "EduPage nepřipojeno" : "EduPage připojeno");
    badge.dataset.eduLabel = labelText;
    badge.setAttribute("aria-label", labelText);
    if(badge.textContent) badge.textContent = "";
    badge.title = detail || "";
    if(normalized !== "loading") topEduLoadingStartedV314 = 0;
  };

  if(topEduStatusTimerV314){
    clearTimeout(topEduStatusTimerV314);
    topEduStatusTimerV314 = null;
  }

  if(normalized === "loading"){
    topEduLoadingStartedV314 = Date.now();
    applyStatus();
    return;
  }

  const loadingAge = topEduLoadingStartedV314 ? Date.now() - topEduLoadingStartedV314 : 1000;
  if(loadingAge < 1000){
    topEduStatusTimerV314 = setTimeout(applyStatus, 1000 - loadingAge);
    return;
  }

  applyStatus();
}

function setPreviewStatusV300(title, detail){
  const preview = document.getElementById("preview");
  if(!preview) return;

  if(/načítám|nacitam|loading/i.test(String(title || ""))){
    return;
  }

  preview.innerHTML = `
    <div class="calendarRequiredV300">
      <div class="calendarRequiredTitleV300">${escapeHtml(title)}</div>
      <div class="calendarRequiredDetailV300">${escapeHtml(detail)}</div>
    </div>
  `;
}

function calendarSignature(eventsList){
  return (eventsList || [])
    .map(e => [
      e.uid || "",
      e.startDate || "",
      e.endDate || "",
      e.startTime || "",
      e.endTime || "",
      e.summary || "",
      e.teachers || "",
      e.classes || ""
    ].join("|"))
    .sort()
    .join("\n");
}

function importWeekFromCalendar(){
  const skipReservations = document.getElementById("skipReservations").checked;
  const skipSubjects = document.getElementById("skipSubjects").checked;
  const includeAllDay = document.getElementById("includeAllDay").checked;

  events = [];
  longEvents = [];

  const from = document.getElementById("weekFrom").value;
  const to = document.getElementById("weekTo").value;
  const weekStart = parseDate(from);
  const weekEnd = parseDate(to);

  function addDaysLocal(date, days){
    const d = new Date(date);
    d.setDate(d.getDate() + days);
    return d;
  }

  function dateOnly(value){
    const d = parseDate(value);
    if(!d) return null;
    d.setHours(0,0,0,0);
    return d;
  }

  function realEndDate(ev){
    const start = dateOnly(ev.startDate);
    let end = dateOnly(ev.endDate || ev.startDate);
    if(!start) return null;
    if(!end) end = new Date(start);

    // U celodenních ICS událostí je DTEND obvykle exkluzivní.
    // Tzn. DTSTART 18.5., DTEND 19.5. = událost jen 18.5.
    if(ev.allDay && ev.endDate && ev.endDate > ev.startDate){
      end = addDaysLocal(end, -1);
    }

    if(end < start) end = new Date(start);
    return end;
  }

  function overlapsWeek(ev){
    const s = dateOnly(ev.startDate);
    const e = realEndDate(ev);
    if(!s || !e || !weekStart || !weekEnd) return false;
    return s <= weekEnd && e >= weekStart;
  }

  function expandTeacherNames(text){ return text ? String(text) : ""; }

  let week = calendarEvents.filter(overlapsWeek);

  if(skipReservations) week = week.filter(e=>!isReservation(e));
  if(skipSubjects) week = week.filter(e=>!isSubjectEvent(e));
  if(!includeAllDay) week = week.filter(e=>!e.allDay);

  week.forEach(e=>{
    const start = dateOnly(e.startDate);
    const end = realEndDate(e);
    if(!start || !end) return;

    let d = new Date(Math.max(start.getTime(), weekStart.getTime()));
    const last = new Date(Math.min(end.getTime(), weekEnd.getTime()));

    while(d <= last){
      const dayKey = dateToInput(d);
      events.push({
        id: uid(),
        uid: e.uid || "",
        source: "calendar",
        date: dayKey,
        from: e.allDay ? "" : (e.startTime || ""),
        to: e.allDay ? "" : (e.endTime || ""),
        title: expandTeacherNames(eventTitleFromCalendar(e)),
        person: expandTeacherNames(eventPersonFromCalendar(e))
      });
      d.setDate(d.getDate() + 1);
    }
  });

  mergeManualEventsV300();
  renderAll();
}

function unfoldIcs(text){
  const lines = text.split(/\r?\n/);
  const out = [];
  lines.forEach(line=>{
    if((line.startsWith(" ") || line.startsWith("\t")) && out.length){
      out[out.length-1] += line.slice(1);
    }else out.push(line);
  });
  return out;
}
function unescapeIcs(s){
  return String(s || "").replace(/\\n/g,"\n").replace(/\\,/g,",").replace(/\\;/g,";").replace(/\\\\/g,"\\");
}
function parseIcsDate(value, allDay){
  if(allDay){
    return {date:`${value.slice(0,4)}-${value.slice(4,6)}-${value.slice(6,8)}`, time:""};
  }
  let v = value.replace("Z","");
  let y=Number(v.slice(0,4)), m=Number(v.slice(4,6)), d=Number(v.slice(6,8)), hh=Number(v.slice(9,11)), mm=Number(v.slice(11,13));
  if(value.endsWith("Z")){
    const dt = new Date(Date.UTC(y,m-1,d,hh,mm));
    // convert to browser local time
    return {date:dateToInput(dt), time:`${pad(dt.getHours())}:${pad(dt.getMinutes())}`};
  }
  return {date:`${y}-${pad(m)}-${pad(d)}`, time:`${pad(hh)}:${pad(mm)}`};
}
function parseIcs(text){
  const lines = unfoldIcs(text);
  const out = [];
  let cur = null;
  lines.forEach(line=>{
    if(line === "BEGIN:VEVENT") cur = {};
    else if(line === "END:VEVENT" && cur){
      out.push(cur); cur = null;
    } else if(cur && line.includes(":")){
      const [left, ...rest] = line.split(":");
      const value = rest.join(":");
      const key = left.split(";")[0];
      cur[key] = unescapeIcs(value);
      cur[key+"_RAW"] = left;
    }
  });

  return out.map(e=>{
    const allDay = /VALUE=DATE/.test(e.DTSTART_RAW || "");
    if(!e.DTSTART) return null;
    const start = parseIcsDate(e.DTSTART, allDay);
    const end = e.DTEND ? parseIcsDate(e.DTEND, allDay) : start;
    const desc = e.DESCRIPTION || "";
    const pick = (label) => {
      const found = desc.split("\n").find(l=>l.startsWith(label+":"));
      return found ? found.replace(label+":","").trim() : "";
    };
    return {
      uid:e.UID || uid(),
      summary:e.SUMMARY || "",
      description:desc,
      location:e.LOCATION || "",
      classes:pick("Třídy"),
      teachers:pick("Učitelé"),
      subject:pick("Předmět"),
      allDay,
      startDate:start.date,
      endDate:end.date,
      startTime:start.time,
      endTime:end.time
    };
  }).filter(Boolean);
}
function importIcsFile(evt){
  const file = evt.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    calendarEvents = parseIcs(reader.result);
    setCalendarInfo();
    alert(`Načteno ${calendarEvents.length} událostí z kalendáře.`);
  };
  reader.readAsText(file, "utf-8");
}

