// Přesná tabulka hodin podle EduPage nastavení ze screenshotu.
const LESSON_TABLE_V161 = [
  {n:0, start:"07:10", end:"07:55"},
  {n:1, start:"08:00", end:"08:45"},
  {n:2, start:"08:55", end:"09:40"},
  {n:3, start:"10:00", end:"10:45"},
  {n:4, start:"10:55", end:"11:40"},
  {n:5, start:"11:50", end:"12:35"},
  {n:6, start:"12:45", end:"13:30"},
  {n:7, start:"13:15", end:"14:00"},
  {n:8, start:"14:00", end:"14:45"},
  {n:9, start:"14:50", end:"15:35"},
  {n:10, start:"15:35", end:"16:20"}
];

function lessonLabelV161(from, to){
  if(!from || !to) return "";

  const s = displayTimeV161(from);
  const e = displayTimeV161(to);

  // Zobrazujeme jen tehdy, když akce přesně začíná začátkem vyučovací hodiny
  // a přesně končí koncem vyučovací hodiny.
  // Proto 14:00–17:00 ani 18:00–20:00 nedostanou chybné hodiny.
  const first = LESSON_TABLE_V161.findIndex(h => h.start === s);
  const last = LESSON_TABLE_V161.findIndex(h => h.end === e);

  if(first === -1 || last === -1 || last < first) return "";

  const a = LESSON_TABLE_V161[first].n;
  const b = LESSON_TABLE_V161[last].n;

  if(a === b) return `${a}. hod.`;
  return `${a}.–${b}. hod.`;
}

function renderTimeCellV161(from, to){
  const f = String(from || "").trim();
  const t = String(to || "").trim();

  if(!f && !t) return `<span class="timeCleanV161"><span class="timeRangeV161">celý den</span></span>`;
  if(f.toLowerCase().includes("celý den") || f.toLowerCase().includes("cely den")) return `<span class="timeCleanV161"><span class="timeRangeV161">celý den</span></span>`;

  if(f && t){
    const range = `${displayTimeV161(f)} - ${displayTimeV161(t)}`;
    const lesson = lessonLabelV161(f, t);
    return `<span class="timeCleanV161"><span class="timeRangeV161">${range}</span>${lesson ? `<span class="lessonV161">${lesson}</span>` : ""}</span>`;
  }

  return `<span class="timeCleanV161"><span class="timeRangeV161">${displayTimeV161(f)}</span></span>`;
}


