function renderPreview(){
  applyDisplayBodyClassesV300();
  const from=document.getElementById("weekFrom").value;
  const to=document.getElementById("weekTo").value;
  const signature=document.getElementById("signature").value;
  const signatureRole=signatureRoleValueV312();
  const weekDates=getWeekDates();
  const planMessage=currentWeekNoteV174();
  const messageHtml = renderPlanNoteSlotV310(planMessage);
  const repeatClasses = repeatClassMapV300(events);

  const rows=[];
  let rowIndex = 0;
  weekDates.forEach(d=>{
    const dateKey=dateToInput(d);
    const dayItems=sortEvents(events.filter(e=>e.date===dateKey))
      .map((event, originalIndex)=>({event, originalIndex}))
      .filter(item=>!isRowDeletedV302(planRowKeyV302(item.event,dateKey,item.originalIndex)));
    const weekendClass = (d.getDay() === 0 || d.getDay() === 6) ? " weekendRowV184" : "";
    if(dayItems.length===0){
      const rowKey = `empty||${dateKey}`;
      const rowChangeControls = renderRowChangeControlsV304(rowKey, [
        {field:"time", original:""},
        {field:"lesson", original:""},
        {field:"title", original:""},
        {field:"person", original:""}
      ]);
      rows.push(`<tr class="dayBreak emptyDayV162${weekendClass}">
        ${renderDayCellV302(dateKey,d,1)}
        ${renderTimeCellFromOriginalsV307(rowKey, "", "")}
        ${renderEditableCellV302("eventCell", rowKey, "title", "", "")}
        ${renderResponsibleCellV300({person:""}, dateKey, rowIndex, rowKey, rowChangeControls)}
      </tr>`);
    }else{
      dayItems.forEach((item,idx)=>{
        const e = item.event;
        const rowKey = planRowKeyV302(e, dateKey, item.originalIndex);
        const repeated = repeatClasses.get(e) || "";
        const rowChangeControls = renderRowChangeControlsV304(rowKey, [
          {field:"time", original:timePlainV302(e)},
          {field:"lesson", original:lessonPlainV302(e)},
          {field:"title", original:String(e.title || "")},
          {field:"person", original:String(e.person || "").trim()}
        ]);
        rows.push(`<tr class="${idx===0?'dayBreak ':''}${repeated}${weekendClass}">
          ${idx===0 ? renderDayCellV302(dateKey,d,dayItems.length) : ""}
          ${renderTimeCellEditableV302(e, rowKey)}
          ${renderEditableCellV302("eventCell", rowKey, "title", String(e.title || ""), renderEventTitleHtmlV306(e))}
          ${renderResponsibleCellV300(e, dateKey, rowIndex, rowKey, `${renderRowDeleteButtonV302(rowKey)}${rowChangeControls}`)}
        </tr>`);
        rowIndex++;
      });
    }
  });

  document.getElementById("preview").innerHTML=`
    <div class="docHeader headerV93">
      <div class="docHeaderTextV93">
        <div class="docSchoolFullV93">Základní škola Brno, Jana Babáka 1, příspěvková organizace</div>
        <div class="docTitle">TÝDENNÍ PLÁN</div>
        <div class="docDates">od ${formatDate(from)} do ${formatDate(to)}</div>
      </div>
      <img class="docLogo" src="src/assets/generated/image-c0d11592a1db.png">
    </div>
    ${messageHtml}
<table class="planTable">
      <colgroup>
        <col class="dateColV308">
        <col class="timeColV308">
        <col class="eventColV308">
        <col class="personColV308">
      </colgroup>
      <thead>
        <tr><th>Datum</th><th>Hodina</th><th>Akce</th><th>Zodpovídá</th></tr>
      </thead>
      <tbody>${rows.join("")}</tbody>
    </table>
    <div class="podpisFinal41">
      <div class="podpisFinal41Box">
        <span class="podpisFinal41Name" contenteditable="true" spellcheck="false" data-signature-name-v310="1">${escapeHtml(signature || DEFAULT_SIGNATURE_V310)}</span><span class="podpisFinal41RolePrefix">, </span><span class="podpisFinal41Role" contenteditable="true" spellcheck="false" data-signature-role-v312="1">${escapeHtml(signatureRole || DEFAULT_SIGNATURE_ROLE_V312)}</span>
      </div>
      ${renderSignatureChangeControlsV310(signature || DEFAULT_SIGNATURE_V310, signatureRole || DEFAULT_SIGNATURE_ROLE_V312)}
    </div>
    <div class="createdDateV184">Vytvořeno: ${todayTextV300()}</div>

    `;
}

